import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"117. Qualification Allowance","description":"","frontmatter":{"title":"117. Qualification Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances","preliminary","classifications"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/117-qualification-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/117-qualification-allowance.md"}'),n={name:"ebas/mental-health/health-professionals/allowances/117-qualification-allowance.md"};function l(r,e,s,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_117-qualification-allowance" tabindex="-1">117. Qualification Allowance <a class="header-anchor" href="#_117-qualification-allowance" aria-label="Permalink to &quot;117. Qualification Allowance&quot;">​</a></h1><p>NOTE: see subclause 9.1(kk) (Definitions) regarding the interpretation of relevance.</p><p><strong>117.1</strong> Entitlement</p><p><strong>(a)</strong> Where an Employee has a relevant qualification in addition to their base relevant health professional qualification, enabling registration or practice under the classification structure the Employee will be entitled to a qualification allowance in accordance with this clause.</p><p><strong>(b)</strong> Where the Employee’s base qualification is a double degree or Masters, the qualification allowance will be payable after one year of experience in an area where the qualification is relevant.</p><p><strong>(c)</strong> The Allowance is to be paid on a pro rata basis for part time and casual Employees.</p><p><strong>117.2</strong> One Qualification Allowance Only An Employee who has more than one qualification is entitled to one qualification allowance only, being the allowance for the highest qualification.</p><p><strong>117.3</strong> Evidence</p><p><strong>(a)</strong> An Employee claiming entitlement to a qualification allowance must provide to the Employer evidence of that Employee having the qualification for which the entitlement is claimed.</p><p><strong>(b)</strong> An Employee will meet the evidence requirements when they have provided the Employer with evidence from the education / training provider that would satisfy a reasonable person that the Employee has obtained the qualification for which the allowance is claimed, for example:</p><p><strong>(i)</strong> the award of the qualification; or</p><p><strong>(ii)</strong> the certificate of the qualification; or</p><p><strong>(iii)</strong> transcript from the education/training provider</p><p><strong>(iv)</strong> payable from the FFPPOA the evidence is provided.</p><p><strong>117.4</strong> Rates for Qualification Allowances A Registered Health Professional shall be entitled to a qualification allowance under this clause will be paid, in addition to the Employee’s salary, as follows:</p><p><strong>(i)</strong> The rate for &#39;AHP1 Graduate Certificate&#39; in Schedule 2for a Graduate Certificate equivalent to within the Australian Qualifications Framework.</p><p><strong>(ii)</strong> The rate for &#39;AHP1 Post Grad Diploma or Degree&#39; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for a Postgraduate Diploma, Degree or a Double Degree.</p><p><strong>(iii)</strong> The rate for &#39;AHP1 Masters&#39; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for a master’s degree.</p><p><strong>(iv)</strong> The rate for &#39;AHP1 PhD&#39; in Schedule 2for a Doctorate or a PhD.</p><p><strong>117.5</strong> Payment During Paid Leave The above Qualification allowances are to be paid during all periods of paid leave.</p>',20)])])}const u=a(n,[["render",l]]);export{d as __pageData,u as default};
